import { useEffect, useState }

from "react";

import axios from "axios";

function AdminDashboard() {

    const [bookings, setBookings] =
        useState([]);

    useEffect(() => {

        fetchBookings();

    }, []);

    const fetchBookings = () => {

        axios
            .get(
                "http://localhost:8081/booking/all"
            )

            .then((response) => {

                setBookings(
                    response.data
                );
            });
    };

    const approveBooking = (id) => {

        axios
            .put(
                `http://localhost:8081/booking/approve/${id}`
            )

            .then(() => {

                alert(
                    "Booking Approved"
                );

                fetchBookings();
            });
    };

    const rejectBooking = (id) => {

        axios
            .put(
                `http://localhost:8081/booking/reject/${id}`
            )

            .then(() => {

                alert(
                    "Booking Rejected"
                );

                fetchBookings();
            });
    };

    return (

        <div
            style={{
                padding: "30px"
            }}
        >

            <h1>

                Admin Dashboard

            </h1>

            <br />

            {
                bookings.map((booking) => (

                    <div

                        key={booking.id}

                        style={{
                            border:
                                "1px solid lightgray",

                            padding: "20px",

                            marginBottom: "20px",

                            borderRadius: "10px"
                        }}
                    >

                        <h2>

                            {
                                booking.carVariant
                                    .variantName
                            }

                        </h2>

                        <p>

                            <b>
                                Customer:
                            </b>

                            {" "}

                            {
                                booking.customer
                                ? booking.customer.name
        : "No Customer"
                            }

                        </p>

                        <p>

                            <b>
                                Total Amount:
                            </b>

                            {" "}

                            ₹ {booking.totalAmount}

                        </p>

                        <p>

                            <b>
                                Status:
                            </b>

                            {" "}

                            {booking.bookingStatus}

                        </p>

                        <button

                            onClick={() =>
                                approveBooking(
                                    booking.id
                                )
                            }

                            style={{
                                backgroundColor:
                                    "green",

                                color: "white",

                                border: "none",

                                padding: "10px",

                                marginRight: "10px"
                            }}
                        >

                            Approve

                        </button>

                        <button

                            onClick={() =>
                                rejectBooking(
                                    booking.id
                                )
                            }

                            style={{
                                backgroundColor:
                                    "red",

                                color: "white",

                                border: "none",

                                padding: "10px"
                            }}
                        >

                            Reject

                        </button>

                    </div>
                ))
            }

        </div>
    );
}

export default AdminDashboard;
